/* Course data for c13–c30 — consumed by scripts/gen-content-ext.js */
function fb(en, zh) { return { en, zh }; }

function mk(en, zh, lblEn, lblZh, board, pot, bet, pos, hand, correct, leak, fbMap, extra) {
  const spec = {
    s: { en, zh },
    lbl: { en: lblEn, zh: lblZh },
    board: board.slice(),
    pot,
    bet,
    pos,
    hand: hand.slice(),
    correct: Array.isArray(correct) ? correct.slice() : [correct],
    leak,
    fb: fbMap || {},
  };
  if (extra) {
    if (extra.street) spec.street = extra.street;
    if (extra.allIn) spec.allIn = true;
    if (extra.ctx) spec.ctx = extra.ctx;
  }
  return spec;
}

function course(id, concept, conceptEn, conceptZh, learn, spots) {
  return { id, concept, conceptEn, conceptZh, learn, spots };
}

